// Simplest program: a string literal handed to log.
// `log` lives in the prelude — see "In scope" on the right.

log("Hello, World");

// ToString is polymorphic — the same function accepts any value.
// Hover a name to see its type; ToString has type `tv_0 -> String`.

log(ToString(42));
log(ToString("hello"));
log(ToString(true));

// Number is a single type — no int/float split.

let pi = 3.14159;
log(ToString(pi));

// `let` introduces a new name for the rest of the program.
// Semicolons separate statements; a trailing one is optional.

let name = "Ada";
log(name);

// Records live in `{ … }` — ADR-009. Structural typing:
// the type is the set of fields, no declaration needed.

let p = { age: 22, name: "John" };
log(p.name);

// Nesting is just a record field whose type is another record.
// Property access chains: `u.user.name`.

let u = { user: { id: 1, name: "Ada" }, active: true };
log(u.user.name);

// `getName` is inferred from its body alone — no annotations.
// Named-arg call sugar: `getName(name: ...)` passes the record.

let getName = r => r.name;
log(getName(name: "Ada", age: 42));
log(getName(name: "Bob", age: 31));

// Field order in a literal doesn't matter for the type — records
// are bags of fields, not sequences.

let mkUser = n => a => { name: n, age: a };
let u = mkUser("Ada")(42);
log(u.name);

// Identity is fully polymorphic: `tv_0 -> tv_0`.
// One type variable carries through.

let id = x => x;
log(ToString(id(42)));

// `twice` takes a function and feeds its output back into it.
// Inferred type: `(tv_0 -> tv_0) -> tv_0 -> tv_0`.

let twice = f => x => f(f(x));
let exclaim = s => concat(s)("!");
log(twice(exclaim)("yo"));

// Function composition with three type variables:
// `compose : (b -> c) -> (a -> b) -> a -> c`.

let compose = f => g => x => f(g(x));
let shout = s => concat(s)("!!!");
let greet = s => concat("Hello, ")(s);
log(compose(shout)(greet)("Ada"));

// Under curried semantics, applying fewer args returns a function
// of the remaining ones. Here `sayHi` is a pre-filled greeter.

let greet = prefix => name => concat(prefix)(name);
let sayHi = greet("Hi, ");
log(sayHi("Ada"));
log(sayHi("Bob"));

// Arrays are homogeneous — every element must share a type.
// Inferred: `Array<Number>`.

let xs = [1, 2, 3];
log(ToString(xs));

// Same shape, different element type — `Array<String>`.

let names = ["Ada", "Bob", "Eve"];
log(ToString(names));

// Records inside arrays share the element type, which is itself
// a record shape. Inferred: `Array<{ x: Number & y: Number }>`.

let points = [
  { x: 1, y: 2 },
  { x: 3, y: 4 }
];
log(ToString(points));

// ToString's type is `tv_0 -> String` — one instantiation per
// call site. Three unrelated argument types, one function.

log(ToString(42));
log(ToString(true));
log(ToString({ x: 1, y: 2 }));

// No annotations anywhere. The type checker works out:
//   greet : String -> String
// from the shape of concat and "Hello, ".

let greet = s => concat("Hello, ")(s);
log(greet("Ada"));

// `getX`'s inferred type is `{ x: tv_0 & y: Number } -> tv_0` —
// both the field set and each field's type come from the call
// sites, with no annotation on `getX`.

let getX = p => p.x;
log(ToString(getX(x: 10, y: 20)));
log(ToString(getX(x: 99, y: 100)));

// Functions are first-class. `apply` has the most general type
// a one-arg higher-order function can have:
//   (tv_0 -> tv_1) -> tv_0 -> tv_1

let apply = f => x => f(x);
let greet = s => concat("Hi, ")(s);
log(apply(greet)("Ada"));

// concat is monomorphic: String -> String -> String.
// Passing a number violates that constraint — the error points
// at the exact mismatch.

concat(42)("hello");

// All array elements must share a type. Mixing Number and String
// has no common type in the prelude, so inference fails.

let bad = [1, "two", 3];
log(ToString(bad));

// You can only apply values whose inferred type is a function.
// x is a Number, so `x(1)` is rejected.

let x = 42;
x(1);

// p's inferred type is `{ x: Number & y: Number }`. Accessing .z
// adds a constraint the record doesn't satisfy → type error.

let p = { x: 1, y: 2 };
log(ToString(p.z));

// useName demands a record with a `name` field. The argument has
// `age` but no `name` — "required field missing" fires.

let useName = r => r.name;
useName(age: 30);

